import React, { useState } from 'react';
import { FaPlane, FaBars, FaTimes, FaUser, FaSignOutAlt, FaTicketAlt } from 'react-icons/fa';
import '../styles/Navbar.css';

const Navbar = ({ isAuthenticated, user, onLoginClick, onSignupClick, onLogout, onMyBookingsClick }) => {
  const [isOpen, setIsOpen] = useState(false);

  const toggleMenu = () => {
    setIsOpen(!isOpen);
  };

  return (
    <nav className="navbar">
      <div className="container nav-container">
        <div className="nav-logo">
          <FaPlane className="logo-icon" />
          <span>BharatFlights</span>
        </div>

        <div className={`nav-menu ${isOpen ? 'active' : ''}`}>
          <ul className="nav-list">
            <li><a href="#home">Home</a></li>
            <li><a href="#flights">Flights</a></li>
            <li><a href="#deals">Domestic Deals</a></li>
            <li><a href="#about">About Us</a></li>
            <li><a href="#contact">Contact</a></li>
          </ul>
          
          <div className="nav-buttons">
            {isAuthenticated ? (
              <>
                <span className="user-welcome">
                  <FaUser /> {user?.name || 'User'}
                </span>
                <button className="btn btn-icon" onClick={onMyBookingsClick}>
                  <FaTicketAlt /> My Bookings
                </button>
                <button className="btn btn-logout" onClick={onLogout}>
                  <FaSignOutAlt /> Logout
                </button>
              </>
            ) : (
              <>
                <button className="btn btn-login" onClick={() => onLoginClick()}>
                  Login
                </button>
                <button className="btn btn-signup" onClick={() => onSignupClick()}>
                  Sign Up
                </button>
              </>
            )}
          </div>
        </div>

        <div className="menu-icon" onClick={toggleMenu}>
          {isOpen ? <FaTimes /> : <FaBars />}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
